const AUTHOR_SCHEMA = {
  type: 'object',
  properties: {
    slug: { type: 'string' }, final_title: { type: 'string' }, final_metaDescription: { type: 'string' },
    words: { type: 'number' }, preview_primary_present: { type: 'boolean' },
    preview_secondary_count: { type: 'number' }, ok: { type: 'boolean' }, error: { type: 'string' },
  },
  required: ['slug', 'final_title', 'final_metaDescription', 'words', 'ok'],
}
const VERIFY_SCHEMA = {
  type: 'object',
  properties: {
    slug: { type: 'string' }, words: { type: 'number' }, language_ok: { type: 'boolean' },
    preview_ok: { type: 'boolean' }, facts_ok: { type: 'boolean' }, fixed: { type: 'boolean' },
    corrections: { type: 'array', items: { type: 'string' } },
    final_title: { type: 'string' }, final_metaDescription: { type: 'string' }, notes: { type: 'string' },
  },
  required: ['slug', 'words', 'language_ok', 'preview_ok', 'facts_ok', 'fixed', 'final_title', 'final_metaDescription'],
}

function authorPrompt(s) {
  const sec = (s.secondary_keywords || []).join(', ')
  return `Esti un expert SENIOR in educatie financiara din Romania si scrii pentru "Clubul Financiar" o lectie PREMIUM de NIVEL AVANSAT (continuare a unei biblioteci de 700 de lectii de baza-intermediar). Continut platit, calitate maxima.

SUBIECT (draft, corecteaza orice greseala): ${s.draft_title}
Categorie: ${CATNAMES[s.category] || s.category}
Se cladeste peste (continuare a): ${s.builds_on || '—'}
Unghi/diferentiator (respecta-l): ${s.angle}
Cuvant-cheie principal (SEO): "${s.primary_keyword}"
Cuvinte-cheie secundare (SEO): ${sec}

NIVEL AVANSAT — esential:
- Cititorul STIE deja bazele (le-a invatat din cele 700 lectii). NU re-explica notiuni elementare; mentioneaza-le scurt si treci la profunzime.
- Nivel: investitor/antreprenor/contribuabil EXPERIMENTAT. Strategii sofisticate, optimizari, cazuri-limita, decizii complexe multi-variabile, capcane subtile, modele de calcul.

CE SCRII:
O lectie COMPLETA si LUNGA (2000-3000 cuvinte de corp), in romana impecabila cu diacritice corecte. DOAR informatii extrem de importante, dense, actionabile. Context ROMANIA 2026: cifre reale in lei, cote, praguri, legislatie/ANAF/BVB/BNR/CNPP exacte, exemple numerice concrete, scenarii pas-cu-pas, comparatii, capcane, pasi de actiune, checklist-uri.

STRUCTURA (fragment HTML de CORP, NU pagina completa):
- Incepe DIRECT cu 2-3 paragrafe <p> de introducere (hook) — FARA titlu, FARA <h1>.
- Apoi sectiuni <h2> (si <h3>), <p>, liste <ul>/<li>, <strong>. Exemple numerice concrete.
- Termina cu o sectiune practica (pasi/checklist) + optional greseli frecvente.
- INTERZIS: <h1>, disclaimer, butoane navigare, markdown, blocuri triple-backtick. Doar HTML curat de corp.

REGULA SEO CRITICA — preview gratuit:
Primele ~25% din lectie sunt vizibile gratuit (indexate de Google), restul e blocat premium. De aceea PRIMELE 2-3 PARAGRAFE (primele ~150-180 de cuvinte, INAINTE de primul <h2>) TREBUIE sa contina NATURAL: (a) "${s.primary_keyword}" — ideal in prima propozitie; (b) MAJORITATEA secundarelor; (c) termenii din titlu. Natural, fluent, fara keyword stuffing.

ACURATETE (cont va fi fact-checkat dupa tine): foloseste DOAR cifre/cote/praguri pe care le stii corecte pentru Romania 2026. Daca nu esti sigur de o cifra exacta, formuleaza prudent (ex. "verifica pragul curent"), NU inventa cifre precise gresite.

PASI:
1. Scrie lectia completa.
2. Salveaz-o cu Write in fisierul EXACT: ${SRC_DIR}/${s.slug}.html (DOAR fragmentul HTML de corp).
3. Finalizeaza un TITLU corect/atractiv si o META DESCRIPTION 140-160 caractere cu "${s.primary_keyword}".
4. Returneaza structura (slug="${s.slug}", final_title, final_metaDescription, words, preview_primary_present, preview_secondary_count, ok).`
}

function verifyPrompt(s) {
  const sec = (s.secondary_keywords || []).join(', ')
  return `Esti redactor-sef + fact-checker la "Clubul Financiar". Verifici RIGUROS si FINALIZEZI o lectie PREMIUM AVANSATA. Fisier: ${SRC_DIR}/${s.slug}.html

Citeste fisierul cu Read. Verifica si CORECTEAZA in fisier (Edit/Write):
1. ACURATETE FACTUALA (cel mai important — utilizatorul vrea informatii CORECTE): fiecare cifra/cota/prag/afirmatie legala pentru Romania 2026 trebuie sa fie CORECTA. Verifica atent: impozit pe venit 10%, dividende 16% (2026), castig de capital broker rezident 3% (>1an)/6% (<1an), broker strain 16% autodeclarat, CASS 10%, CAS 25%, plafoane micro/TVA, Pilon II 4,75%, deducere Pilon III 400 EUR, salariu minim, praguri CASS pe venituri etc. Daca o cifra e gresita sau inventata, CORECTEAZA-O cu valoarea reala 2026; daca nu poate fi verificata cu certitudine, reformuleaza prudent (fara cifra falsa). Listeaza corecturile in "corrections".
2. LIMBA: romana impecabila, diacritice corecte, FARA text amestecat/cuvinte straine nejustificate, fara typo-uri/dezacorduri. Rescrie frazele stricate.
3. NIVEL AVANSAT: chiar e avansat (nu re-explica bazele banal)? Daca e prea elementar, ridica nivelul.
4. LUNGIME: minim ~1800 de cuvinte de corp. Daca e scurt, extinde cu continut valoros.
5. SEO PREVIEW: primele ~180 de cuvinte (inainte de primul <h2>) contin "${s.primary_keyword}" + majoritatea secundarelor (${sec}). Daca nu, rescrie introducerea natural.
6. STRUCTURA HTML: doar fragment de corp (<p>,<h2>,<h3>,<ul>,<li>,<strong>); FARA <h1>, disclaimer, markdown, triple-backtick. Curata.

Daca e deja excelenta si corecta, las-o. Returneaza: slug="${s.slug}", words, language_ok, preview_ok, facts_ok (true daca informatiile sunt corecte dupa verificare), fixed, corrections (lista scurta a corecturilor factuale facute), final_title, final_metaDescription (140-160 char), notes (scurt).`
}

log(`Pornesc redactarea a ${SPECS.length} lectii AVANSATE (autor -> verificare riguroasa de corectitudine).`)
const results = await pipeline(
  SPECS,
  (s) => agent(authorPrompt(s), { label: `author:${s.slug}`, phase: 'Author', schema: AUTHOR_SCHEMA, agentType: 'general-purpose', effort: 'high' })
            .then(r => ({ ...(r || {}), slug: s.slug })),
  (authored, s) => agent(verifyPrompt(s), { label: `verify:${s.slug}`, phase: 'Verify', schema: VERIFY_SCHEMA, agentType: 'general-purpose', effort: 'high' })
            .then(v => ({ slug: s.slug, category: s.category, author: authored, verify: v || null }))
)
const done = results.filter(Boolean)
const failed = SPECS.filter(s => !done.find(d => d.slug === s.slug)).map(s => s.slug)
log(`Redactare terminata: ${done.length}/${SPECS.length}. Esuate: ${failed.length}`)
return { done, failed }
